#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point(int _x = 0, int _y = 0) : x(_x), y(_y) {}

    void display() const {
        std::cout << "(" << x << ", " << y << ")";
    }

    Point operator+(const Point& other) const {
        return Point(x + other.x, y + other.y);
    }
};

int main() {
    Point p1(10, 20);
    Point p2(3, 7);
    Point p3 = p1 + p2;
    p3.display();
    std::cout << "\n";

    Point p4(0, 0);
    Point p5(-5, 12);
    Point p6 = p4 + p5;
    p6.display();
    std::cout << "\n";

    return 0;
}
